#ifdef __cplusplus
extern "C" {
#endif

#include <stdlib.h>
#include <stdio.h>
#include <math.h>

#include "main.h"

#include "kernel_cpu.h"

#include <cuda_runtime.h>
#include "device.h"

#define CUDA_CHECK_ERROR() { checkCUDAError("CUDA kernel launch"); }

__device__ inline fp dev_DOT(const FOUR_VECTOR &A, const FOUR_VECTOR &B) {
    return A.x*B.x + A.y*B.y + A.z*B.z;
}

__global__ void kernel_gpu_cuda(	par_str par, 
									dim_str dim,
									box_str* box,
									FOUR_VECTOR* rv,
									fp* qv,
									FOUR_VECTOR* fv)
{
	long l = blockIdx.x;
	int i = threadIdx.x;

	if (l >= dim.number_boxes || i >= NUMBER_PAR_PER_BOX) return;

	fp alpha = par.alpha;
	fp a2 = 2.0 * alpha * alpha;

	long first_i = box[l].offset;
	FOUR_VECTOR* rA = &rv[first_i];
	FOUR_VECTOR* fA = &fv[first_i];

	FOUR_VECTOR rA_i = rA[i];

	for (int k = 0; k < (1 + box[l].nn); k++) {
		int pointer;
		if (k == 0) {
			pointer = l;
		} else {
			pointer = box[l].nei[k - 1].number;
		}

		long first_j = box[pointer].offset;
		FOUR_VECTOR* rB = &rv[first_j];
		fp* qB = &qv[first_j];

		fp fA_v = 0.0;
		fp fA_x = 0.0;
		fp fA_y = 0.0;
		fp fA_z = 0.0;

		for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
			fp r2 = rA_i.v + rB[j].v - dev_DOT(rA_i, rB[j]);
			fp u2 = a2 * r2;
			fp vij = exp(-u2);
			fp fs = 2.0 * vij;
			fp dx = rA_i.x - rB[j].x;
			fp dy = rA_i.y - rB[j].y;
			fp dz = rA_i.z - rB[j].z;
			fp fxij = fs * dx;
			fp fyij = fs * dy;
			fp fzij = fs * dz;

			fA_v += qB[j] * vij;
			fA_x += qB[j] * fxij;
			fA_y += qB[j] * fyij;
			fA_z += qB[j] * fzij;
		}

		atomicAdd(&fA[i].v, fA_v);
		atomicAdd(&fA[i].x, fA_x);
		atomicAdd(&fA[i].y, fA_y);
		atomicAdd(&fA[i].z, fA_z);
	}
}

void kernel_cpu(	par_str par, 
					dim_str dim,
					box_str* box,
					FOUR_VECTOR* rv,
					fp* qv,
					FOUR_VECTOR* fv)
{
	long long time0 = get_time();
	long long time1, time2, time3, time4;

	time1 = get_time();

	setdevice();
	CUDA_CHECK_ERROR();

	time2 = get_time();

	time3 = get_time();

	box_str* d_box;
	FOUR_VECTOR* d_rv;
	fp* d_qv;
	FOUR_VECTOR* d_fv;

	cudaMalloc((void**)&d_box, dim.box_mem);
	cudaMalloc((void**)&d_rv, dim.space_mem);
	cudaMalloc((void**)&d_qv, dim.space_mem2);
	cudaMalloc((void**)&d_fv, dim.space_mem);

	CUDA_CHECK_ERROR();

	cudaMemcpy(d_box, box, dim.box_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(d_rv, rv, dim.space_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(d_qv, qv, dim.space_mem2, cudaMemcpyHostToDevice);
	cudaMemset(d_fv, 0, dim.space_mem);

	CUDA_CHECK_ERROR();

	time4 = get_time();

	dim3 grid(dim.number_boxes, 1, 1);
	dim3 block(NUMBER_PAR_PER_BOX, 1, 1);

	kernel_gpu_cuda<<<grid, block>>>(par, dim, d_box, d_rv, d_qv, d_fv);
	cudaDeviceSynchronize();
	CUDA_CHECK_ERROR();

	long long time5 = get_time();

	cudaMemcpy(fv, d_fv, dim.space_mem, cudaMemcpyDeviceToHost);
	CUDA_CHECK_ERROR();

	long long time6 = get_time();

	cudaFree(d_box);
	cudaFree(d_rv);
	cudaFree(d_qv);
	cudaFree(d_fv);

	long long time7 = get_time();

	printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
	printf("%15.12f s, %15.12f % : CPU/MCPU: VARIABLES\n",				(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time7-time0) * 100);
	printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n",					(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time7-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU/MCPU: INPUTS\n", 				(float) (time4-time2) / 1000000, (float) (time4-time2) / (float) (time7-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n",					(float) (time6-time4) / 1000000, (float) (time6-time4) / (float) (time7-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU/MCPU: COPY BACK\n",				(float) (time7-time6) / 1000000, (float) (time7-time6) / (float) (time7-time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", 												(float) (time7-time0) / 1000000);
}

#ifdef __cplusplus
}
#endif

